    ->furkotAuthAccessCodeCredentials(
        FurkotAuthAccessCodeCredentialsBuilder::init(
            'OAuthClientId',
            'OAuthClientSecret',
            'OAuthRedirectUri'
        )
            ->oAuthScopes(
                [
                    OAuthScopeFurkotAuthAccessCodeEnum::READTRIPS
                ]
